export const evidencePlaceholder = `${import.meta.env.BASE_URL}assets/svg/evidence-placeholder.svg`;

export function getEvidenceSvg(ref: string, fallback?: string) {
  if (fallback) return fallback.startsWith("/") ? `${import.meta.env.BASE_URL}${fallback.slice(1)}` : fallback;
  if (evidenceAssets[ref]) return evidenceAssets[ref];
  const normalized = ref.toLowerCase().replace(/\s+/g, " ").trim();
  const found = Object.keys(evidenceAssets).find((key) => {
    const k = key.toLowerCase().replace(/\s+/g, " ").trim();
    return k === normalized || normalized.startsWith(k) || k.startsWith(normalized);
  });
  return found ? evidenceAssets[found] : evidencePlaceholder;
}